  background: var(--bg-tertiary);
}

#chat-input {
  flex: 1;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 10px 14px;
  font-family: var(--font-sans);
  font-size: 14px;
  color: var(--text-primary);
  min-height: 20px;
}

#chat-input-text {
  white-space: pre-wrap;
}

.blink {
  animation: blink 1s infinite;
  color: var(--text-secondary);
  font-weight: 300;
}

@keyframes blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

#chat-send-btn {
  background: var(--blue);
  border: none;
  border-radius: 8px;
  padding: 8px;
  cursor: pointer;
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: opacity 0.2s;
}

#chat-send-btn:hover {
  opacity: 0.8;
}

/* ── Right Panel ── */
#right-panel-header {
  display: flex;
  align-items: center;
  padding: 12px 16px;
  background: var(--bg-tertiary);
  border-bottom: 1px solid var(--border);
}

.right-panel-title {
  font-size: 13px;
  font-weight: 500;
  color: var(--text-secondary);
  font-family: var(--font-mono);
}

#right-panel-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.6;
}

/* ── JSON Syntax Highlighting ── */
.json-key { color: var(--blue); }
.json-string { color: var(--green); }
.json-number { color: var(--orange); }
.json-boolean { color: var(--purple); }
.json-null { color: var(--text-muted); }
.json-bracket { color: var(--text-secondary); }
.json-punctuation { color: var(--text-secondary); }

.json-block {
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 16px;
  margin-bottom: 12px;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-word;
}

.json-block.highlight-new {
  animation: highlightPulse 1s ease;
}

@keyframes highlightPulse {
  0% { border-color: var(--blue); box-shadow: 0 0 15px rgba(88, 166, 255, 0.3); }
  100% { border-color: var(--border); box-shadow: none; }
}

/* ── Context sections ── */
.context-section {
  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 12px;
  border: 1px solid;
  animation: messageIn 0.3s ease;
}

.context-section.system {
  background: var(--purple-dim);
  border-color: rgba(188, 140, 255, 0.3);
}

.context-section.user-msg {
  background: var(--blue-dim);
  border-color: rgba(88, 166, 255, 0.3);
}

.context-section.assistant-msg {
  background: var(--green-dim);
  border-color: rgba(63, 185, 80, 0.3);
}

.context-section.thinking {
  background: var(--purple-dim);
  border-color: rgba(188, 140, 255, 0.3);
}

.context-section.tool-call {
  background: var(--orange-dim);
  border-color: rgba(210, 153, 34, 0.3);
}

.context-section.tool-result {
  background: var(--cyan-dim);
  border-color: rgba(57, 210, 192, 0.3);
}

.context-section.rag {
  background: var(--yellow-dim);
  border-color: rgba(227, 179, 65, 0.3);
}

.context-label {
  font-family: var(--font-mono);
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 6px;
}

.context-label .dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  display: inline-block;
}

.context-section.system .context-label { color: var(--purple); }
.context-section.system .dot { background: var(--purple); }
.context-section.user-msg .context-label { color: var(--blue); }
.context-section.user-msg .dot { background: var(--blue); }
.context-section.assistant-msg .context-label { color: var(--green); }
.context-section.assistant-msg .dot { background: var(--green); }
.context-section.thinking .context-label { color: var(--purple); }
.context-section.thinking .dot { background: var(--purple); }
.context-section.tool-call .context-label { color: var(--orange); }
.context-section.tool-call .dot { background: var(--orange); }
.context-section.tool-result .context-label { color: var(--cyan); }
.context-section.tool-result .dot { background: var(--cyan); }
.context-section.rag .context-label { color: var(--yellow); }
.context-section.rag .dot { background: var(--yellow); }

.context-body {
  font-family: var(--font-mono);
  font-size: 12.5px;
  color: var(--text-secondary);
  white-space: pre-wrap;
  word-break: break-word;
}

/* ── Agent Loop Diagram ── */
.loop-diagram {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0;
  padding: 20px 10px;
}

.loop-step {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 20px;
  border-radius: 8px;
  font-family: var(--font-mono);
  font-size: 13px;
  font-weight: 500;
  opacity: 0;
  transform: translateY(10px);
  transition: opacity 0.4s ease, transform 0.4s ease, box-shadow 0.3s ease;
  min-width: 280px;
  justify-content: center;
}

.loop-step.visible {
  opacity: 1;
  transform: translateY(0);
}

.loop-step.active {
  box-shadow: 0 0 20px rgba(88, 166, 255, 0.2);
}

.loop-step.user-step {
  background: var(--blue-dim);
  border: 1px solid rgba(88, 166, 255, 0.3);
  color: var(--blue);
}

.loop-step.model-step {
  background: var(--green-dim);
  border: 1px solid rgba(63, 185, 80, 0.3);
  color: var(--green);
}

.loop-step.tool-step {
  background: var(--orange-dim);
  border: 1px solid rgba(210, 153, 34, 0.3);
  color: var(--orange);
}

.loop-step.harness-step {
  background: var(--cyan-dim);
  border: 1px solid rgba(57, 210, 192, 0.3);
  color: var(--cyan);
}

.loop-step.response-step {
  background: var(--green-dim);
  border: 1px solid rgba(63, 185, 80, 0.3);
  color: var(--green);
}

.loop-arrow {
  font-size: 20px;
  color: var(--text-muted);
  opacity: 0;
  transition: opacity 0.3s ease;
  line-height: 1;
  padding: 4px 0;
}

.loop-arrow.visible {
  opacity: 1;
}

.loop-label {
  font-family: var(--font-sans);
  font-size: 12px;
  color: var(--text-muted);
  text-align: center;
  opacity: 0;
  transition: opacity 0.3s ease;
  margin-top: 4px;
  font-style: italic;
}

.loop-label.visible {
  opacity: 1;
}

.loop-brace {
  position: relative;
  margin: 4px 0;
  opacity: 0;
  transition: opacity 0.4s ease;
}

.loop-brace.visible {
  opacity: 1;
}

.loop-brace-label {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--orange);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

/* ── RAG Flow ── */
.rag-flow {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0;
  padding: 10px;
}

.rag-step {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 20px;
  border-radius: 8px;
  font-family: var(--font-mono);
  font-size: 13px;
  font-weight: 500;
  opacity: 0;
  transform: translateY(10px);
  transition: opacity 0.4s ease, transform 0.4s ease;
  min-width: 280px;
  justify-content: center;
}

.rag-step.visible {
  opacity: 1;
  transform: translateY(0);
}

.rag-step.query-step {
  background: var(--blue-dim);
  border: 1px solid rgba(88, 166, 255, 0.3);
  color: var(--blue);
}

.rag-step.search-step {
  background: var(--yellow-dim);
  border: 1px solid rgba(227, 179, 65, 0.3);
  color: var(--yellow);
}

.rag-step.retrieve-step {
  background: var(--yellow-dim);
  border: 1px solid rgba(227, 179, 65, 0.3);
  color: var(--yellow);
}

.rag-step.inject-step {
  background: var(--cyan-dim);
  border: 1px solid rgba(57, 210, 192, 0.3);
  color: var(--cyan);
}

.rag-step.model-step {
  background: var(--green-dim);
  border: 1px solid rgba(63, 185, 80, 0.3);
  color: var(--green);
}

.rag-arrow {
  font-size: 20px;
  color: var(--text-muted);
  opacity: 0;
  transition: opacity 0.3s ease;
  line-height: 1;
  padding: 4px 0;
}

.rag-arrow.visible {
  opacity: 1;
}

/* ── Skills ── */
.skill-expansion {
  margin-top: 8px;
}

.skill-expansion .arrow-down {
  text-align: center;
  font-size: 20px;
  color: var(--text-muted);
  padding: 4px 0;
}

/* ── Conclusion Full Picture ── */
.full-picture {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 10px;
}

.full-picture .context-section {
  margin-bottom: 0;
  padding: 8px 12px;
}

.full-picture .context-body {
  font-size: 11.5px;
}

.conclusion-title {
  font-family: var(--font-mono);
  font-size: 20px;
  font-weight: 600;
  text-align: center;
  color: var(--text-primary);
  padding: 16px;
  margin-bottom: 8px;
  background: linear-gradient(135deg, var(--purple-dim), var(--blue-dim));
  border-radius: 12px;
  border: 1px solid rgba(188, 140, 255, 0.3);
}

.built-with-agent {
  font-family: var(--font-sans);
  font-size: 14px;
  text-align: center;
  color: var(--text-secondary);
  padding: 12px;
  margin-top: 8px;
  opacity: 0;
  transition: opacity 0.6s ease;
  font-style: italic;
}

.built-with-agent.visible {
  opacity: 1;
}

/* ── Context Window Bar ── */
.context-bar-container {
  padding: 0 0 12px 0;
}

.context-bar-label {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
  margin-bottom: 6px;
  display: flex;
  justify-content: space-between;
}

.context-bar {
  height: 6px;
  background: var(--bg-primary);
  border-radius: 3px;
  overflow: hidden;
  border: 1px solid var(--border);
}

.context-bar-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--blue), var(--purple));
  border-radius: 3px;
  transition: width 0.6s cubic-bezier(0.4, 0, 0.2, 1);
  width: 0%;
}

/* ── Progress Bar ── */
#progress-bar {
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 16px;
  background: var(--bg-primary);
  border-top: 1px solid var(--border);
  padding: 0 20px;
}

#progress-dots {
  display: flex;
  gap: 8px;
}

.progress-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--text-muted);
  transition: background 0.3s ease, transform 0.3s ease;
  cursor: pointer;
}

.progress-dot.active {
  background: var(--blue);
  transform: scale(1.3);
}

.progress-dot.completed {
  background: var(--text-secondary);
}

#progress-label {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
}

/* ── Scrollbar ── */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--text-muted);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--text-secondary);
}

/* ── Message code blocks ── */
.message code {
  font-family: var(--font-mono);
  font-size: 13px;
  background: var(--bg-primary);
  padding: 2px 6px;
  border-radius: 4px;
}

/* ── Utility ── */
.hidden {
  display: none !important;
}

.fade-in {
  animation: fadeIn 0.4s ease;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

input.content:
// ── Demystifying Agents - Presentation Engine ──

// ── Step definitions ──
// Each step is { stage, action } where action is a function.
// ArrowRight advances to the next step, ArrowLeft goes back.

const steps = [];
let currentStep = -1;
let isAnimating = false;

// ── DOM refs ──
const leftPanel = document.getElementById('left-panel');
const rightPanel = document.getElementById('right-panel');
const chatMessages = document.getElementById('chat-messages');
const chatInputText = document.getElementById('chat-input-text');
const chatCursor = document.getElementById('chat-cursor');
const rightPanelContent = document.getElementById('right-panel-content');
const rightPanelTitle = document.querySelector('.right-panel-title');
const progressDots = document.getElementById('progress-dots');
const progressLabel = document.getElementById('progress-label');

// ── State tracking for undo ──
// Each step records what it added so we can reverse it
const stateStack = [];

const STAGE_NAMES = [
  '',
  'The Chat Interface',
  'The Context Window',
  'Reasoning Models',
  'Tool Calling',
  'RAG',
  'System Prompts',
  'Skills',
  'Conclusion'
];

const TOTAL_STAGES = 8;

// ── Utility functions ──

function scrollChatToBottom() {
  chatMessages.scrollTop = chatMessages.scrollHeight;
}

function addChatMessage(role, html) {
  const msg = document.createElement('div');
  msg.className = `message ${role}`;
  msg.innerHTML = html;
  chatMessages.appendChild(msg);
  scrollChatToBottom();
  return msg;
}

function removeChatMessage(msg) {
  if (msg && msg.parentNode) {
    msg.parentNode.removeChild(msg);
  }
}

function showTypingIndicator() {
  const msg = document.createElement('div');
  msg.className = 'message assistant';
  msg.id = 'typing-indicator';
  msg.innerHTML = '<div class="typing-indicator"><span></span><span></span><span></span></div>';
  chatMessages.appendChild(msg);
  scrollChatToBottom();
  return msg;
}

function removeTypingIndicator() {
  const el = document.getElementById('typing-indicator');
  if (el) el.remove();
}

function setInputText(text) {
  chatInputText.textContent = text;
}

function clearInput() {
  chatInputText.textContent = '';
}

function showRightPanel() {
  leftPanel.classList.remove('full-width');
  leftPanel.classList.add('split');
  rightPanel.classList.add('visible');
}

function hideRightPanel() {
  leftPanel.classList.add('full-width');
  leftPanel.classList.remove('split');
  rightPanel.classList.remove('visible');
}

function setRightPanelContent(html) {
  rightPanelContent.innerHTML = html;
}

function appendRightPanelContent(html) {
  rightPanelContent.innerHTML += html;
  rightPanelContent.scrollTop = rightPanelContent.scrollHeight;
}

// ── Progress bar ──

function initProgressBar() {
  progressDots.innerHTML = '';
  for (let i = 1; i <= TOTAL_STAGES; i++) {
    const dot = document.createElement('div');
    dot.className = 'progress-dot';
    dot.dataset.stage = i;
    progressDots.appendChild(dot);
  }
  updateProgressBar(1);
}

function updateProgressBar(stage) {
  const dots = progressDots.querySelectorAll('.progress-dot');
  dots.forEach(dot => {
    const s = parseInt(dot.dataset.stage);
    dot.className = 'progress-dot';
    if (s < stage) dot.classList.add('completed');
    else if (s === stage) dot.classList.add('active');
  });
  progressLabel.textContent = `${stage} / ${TOTAL_STAGES}  ${STAGE_NAMES[stage] || ''}`;
}

// ── Step builder helpers ──

function addStep(stage, forward, backward) {
  steps.push({ stage, forward, backward });
}

// ── Define all presentation steps ──

function defineSteps() {

  // ════════════════════════════════════════
  // STAGE 1: The Chat Interface
  // ════════════════════════════════════════

  // Step: Show empty chat (initial state)
  addStep(1,
    () => {
      hideRightPanel();
      clearInput();
    },
    () => {}
  );

  // Step: User types question in input
  addStep(1,
    () => { setInputText('What is the capital of France?'); },
    () => { clearInput(); }
  );

  // Step: User "sends" the message
  let msg1user;
  addStep(1,
    () => {
      clearInput();
      msg1user = addChatMessage('user', 'What is the capital of France?');
    },
    () => {
      removeChatMessage(msg1user);
      setInputText('What is the capital of France?');
    }
  );

  // Step: Typing indicator
  let typing1;
  addStep(1,
    () => { typing1 = showTypingIndicator(); },
    () => { removeTypingIndicator(); }
  );

  // Step: Assistant responds
  let msg1asst;
  addStep(1,
    () => {
      removeTypingIndicator();
      msg1asst = addChatMessage('assistant', 'The capital of France is Paris. It\'s the largest city in France and serves as the country\'s political, economic, and cultural centre.');
    },
    () => {
      removeChatMessage(msg1asst);
      showTypingIndicator();
    }
  );

  // Step: User types second question
  addStep(1,
    () => { setInputText('What about Germany?'); },
    () => { clearInput(); }
  );

  // Step: User sends second message
  let msg2user;
  addStep(1,
    () => {
      clearInput();
      msg2user = addChatMessage('user', 'What about Germany?');
    },
    () => {
      removeChatMessage(msg2user);
      setInputText('What about Germany?');
    }
  );

  // Step: Typing indicator
  addStep(1,
    () => { showTypingIndicator(); },
    () => { removeTypingIndicator(); }
  );

  // Step: Assistant responds
  let msg2asst;
  addStep(1,
    () => {
      removeTypingIndicator();
      msg2asst = addChatMessage('assistant', 'The capital of Germany is Berlin. It\'s the largest city in Germany and has a rich history, particularly during the Cold War when it was divided into East and West Berlin.');
    },
    () => {
      removeChatMessage(msg2asst);
      showTypingIndicator();
    }
  );

  // ════════════════════════════════════════
  // STAGE 2: The Context Window
  // ════════════════════════════════════════

  // Step: Reveal the right panel
  addStep(2,
    () => {
      showRightPanel();
      rightPanelTitle.textContent = 'Under the Hood — API Request';
      setRightPanelContent(`
        <div class="context-bar-container">
          <div class="context-bar-label">
            <span>Context Window</span>
            <span id="context-pct">8%</span>
          </div>
          <div class="context-bar"><div class="context-bar-fill" id="context-fill" style="width: 8%"></div></div>
        </div>
        <div id="context-sections"></div>
      `);
      // Show the context from the existing conversation
      document.getElementById('context-sections').innerHTML = `
        <div class="context-section user-msg highlight-new">
          <div class="context-label"><span class="dot"></span> User</div>
          <div class="context-body">What is the capital of France?</div>
        </div>
        <div class="context-section assistant-msg">
          <div class="context-label"><span class="dot"></span> Assistant</div>
          <div class="context-body">The capital of France is Paris. It's the largest city in France and serves as the country's political, economic, and cultural centre.</div>
        </div>
        <div class="context-section user-msg">
          <div class="context-label"><span class="dot"></span> User</div>
          <div class="context-body">What about Germany?</div>
        </div>
        <div class="context-section assistant-msg">
          <div class="context-label"><span class="dot"></span> Assistant</div>
          <div class="context-body">The capital of Germany is Berlin. It's the largest city in Germany and has a rich history, particularly during the Cold War when it was divided into East and West Berlin.</div>
        </div>
      `;
    },
    () => {
      hideRightPanel();
      setRightPanelContent('');
    }
  );

  // Step: User asks another question (context grows)
  addStep(2,
    () => { setInputText('And Spain?'); },
    () => { clearInput(); }
  );

  let msg3user;
  addStep(2,
    () => {
      clearInput();
      msg3user = addChatMessage('user', 'And Spain?');
      // Add to context view
      const sections = document.getElementById('context-sections');
      if (sections) {
        sections.innerHTML += `
          <div class="context-section user-msg highlight-new">
            <div class="context-label"><span class="dot"></span> User</div>
            <div class="context-body">And Spain?</div>
          </div>
        `;
        rightPanelContent.scrollTop = rightPanelContent.scrollHeight;
      }
      const fill = document.getElementById('context-fill');
      const pct = document.getElementById('context-pct');
      if (fill) fill.style.width = '10%';
      if (pct) pct.textContent = '10%';
    },
    () => {
      removeChatMessage(msg3user);
      setInputText('And Spain?');
      // Remove last context section
      const sections = document.getElementById('context-sections');
      if (sections && sections.lastElementChild) {
        sections.removeChild(sections.lastElementChild);
      }
      const fill = document.getElementById('context-fill');
      const pct = document.getElementById('context-pct');
      if (fill) fill.style.width = '8%';
      if (pct) pct.textContent = '8%';
    }
  );

  addStep(2,
    () => { showTypingIndicator(); },
    () => { removeTypingIndicator(); }
  );

  let msg3asst;
  addStep(2,
    () => {
      removeTypingIndicator();
      msg3asst = addChatMessage('assistant', 'The capital of Spain is Madrid. It\'s located in the centre of the Iberian Peninsula and is known for its rich cultural heritage, including the Prado Museum and the Royal Palace.');
      const sections = document.getElementById('context-sections');
      if (sections) {
        sections.innerHTML += `
          <div class="context-section assistant-msg highlight-new">
            <div class="context-label"><span class="dot"></span> Assistant</div>
            <div class="context-body">The capital of Spain is Madrid. It's located in the centre of the Iberian Peninsula and is known for its rich cultural heritage.</div>
          </div>
        `;
        rightPanelContent.scrollTop = rightPanelContent.scrollHeight;
      }
      const fill = document.getElementById('context-fill');
      const pct = document.getElementById('context-pct');
      if (fill) fill.style.width = '14%';
      if (pct) pct.textContent = '14%';
    },
    () => {
      removeChatMessage(msg3asst);
      showTypingIndicator();
      const sections = document.getElementById('context-sections');
      if (sections && sections.lastElementChild) {
        sections.removeChild(sections.lastElementChild);
      }
      const fill = document.getElementById('context-fill');
      const pct = document.getElementById('context-pct');
      if (fill) fill.style.width = '10%';
      if (pct) pct.textContent = '10%';
    }
  );

  // Step: Highlight callout - "The ENTIRE conversation is sent every time"
  addStep(2,
    () => {
      const sections = document.getElementById('context-sections');
      if (sections) {
