 107→function initProgressBar() {
 108→  progressDots.innerHTML = '';
 109→  for (let i = 1; i <= TOTAL_STAGES; i++) {
 110→    const dot = document.createElement('div');
 111→    dot.className = 'progress-dot';
 112→    dot.dataset.stage = i;
 113→    progressDots.appendChild(dot);
 114→  }
 115→  updateProgressBar(1);
 116→}
 117→
 118→function updateProgressBar(stage) {
 119→  const dots = progressDots.querySelectorAll('.progress-dot');
 120→  dots.forEach(dot => {
 121→    const s = parseInt(dot.dataset.stage);
 122→    dot.className = 'progress-dot';
 123→    if (s < stage) dot.classList.add('completed');
 124→    else if (s === stage) dot.classList.add('active');
 125→  });
 126→  progressLabel.textContent = `${stage} / ${TOTAL_STAGES}  ${STAGE_NAMES[stage] || ''}`;
 127→}
