1185→  if (currentStep >= steps.length - 1) return;
1186→
1187→  currentStep++;
1188→  const step = steps[currentStep];
1189→  step.forward();
1190→  updateProgressBar(step.stage);
1191→}
1192→
1193→function goBack() {
1194→  if (isAnimating) return;
1195→  if (currentStep < 0) return;
1196→
1197→  const step = steps[currentStep];
1198→  step.backward();
1199→  currentStep--;
1200→
1201→  if (currentStep >= 0) {
1202→    updateProgressBar(steps[currentStep].stage);
1203→  } else {
1204→    updateProgressBar(1);
1205→  }
