.context-label .dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  display: inline-block;
}

.context-section.system .context-label { color: var(--purple); }
.context-section.system .dot { background: var(--purple); }
.context-section.user-msg .context-label { color: var(--blue); }
.context-section.user-msg .dot { background: var(--blue); }
.context-section.assistant-msg .context-label { color: var(--green); }
.context-section.assistant-msg .dot { background: var(--green); }
.context-section.thinking .context-label { color: var(--purple); }
.context-section.thinking .dot { background: var(--purple); }
.context-section.tool-call .context-label { color: var(--orange); }
.context-section.tool-call .dot { background: var(--orange); }
.context-section.tool-result .context-label { color: var(--cyan); }
.context-section.tool-result .dot { background: var(--cyan); }
.context-section.rag .context-label { color: var(--yellow); }
.context-section.rag .dot { background: var(--yellow); }

.context-body {
  font-family: var(--font-mono);
  font-size: 12.5px;
  color: var(--text-secondary);
  white-space: pre-wrap;
  word-break: break-word;
}

/* ── Agent Loop Diagram ── */
.loop-diagram {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0;
  padding: 20px 10px;
}

.loop-step {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 20px;
  border-radius: 8px;
  font-family: var(--font-mono);
  font-size: 13px;
  font-weight: 500;
  opacity: 0;
  transform: translateY(10px);
  transition: opacity 0.4s ease, transform 0.4s ease, box-shadow 0.3s ease;
  min-width: 280px;
  justify-content: center;
}

.loop-step.visible {
  opacity: 1;
  transform: translateY(0);
}

.loop-step.active {
  box-shadow: 0 0 20px rgba(88, 166, 255, 0.2);
}

.loop-step.user-step {
  background: var(--blue-dim);
  border: 1px solid rgba(88, 166, 255, 0.3);
  color: var(--blue);
}

.loop-step.model-step {
  background: var(--green-dim);
  border: 1px solid rgba(63, 185, 80, 0.3);
  color: var(--green);
}

.loop-step.tool-step {
  background: var(--orange-dim);
  border: 1px solid rgba(210, 153, 34, 0.3);
  color: var(--orange);
}

.loop-step.harness-step {
  background: var(--cyan-dim);
  border: 1px solid rgba(57, 210, 192, 0.3);
  color: var(--cyan);
}

.loop-step.response-step {
  background: var(--green-dim);
  border: 1px solid rgba(63, 185, 80, 0.3);
  color: var(--green);
}

.loop-arrow {
  font-size: 20px;
  color: var(--text-muted);
  opacity: 0;
  transition: opacity 0.3s ease;
  line-height: 1;
  padding: 4px 0;
}

.loop-arrow.visible {
  opacity: 1;
}

.loop-label {
  font-family: var(--font-sans);
  font-size: 12px;
  color: var(--text-muted);
  text-align: center;
  opacity: 0;
  transition: opacity 0.3s ease;
  margin-top: 4px;
  font-style: italic;
}

.loop-label.visible {
  opacity: 1;
}

.loop-brace {
  position: relative;
  margin: 4px 0;
  opacity: 0;
  transition: opacity 0.4s ease;
}

.loop-brace.visible {
  opacity: 1;
}

.loop-brace-label {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--orange);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

/* ── RAG Flow ── */
.rag-flow {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0;
  padding: 10px;
}

.rag-step {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 20px;
  border-radius: 8px;
  font-family: var(--font-mono);
  font-size: 13px;
  font-weight: 500;
  opacity: 0;
  transform: translateY(10px);
  transition: opacity 0.4s ease, transform 0.4s ease;
  min-width: 280px;
  justify-content: center;
}

.rag-step.visible {
  opacity: 1;
  transform: translateY(0);
}

.rag-step.query-step {
  background: var(--blue-dim);
  border: 1px solid rgba(88, 166, 255, 0.3);
  color: var(--blue);
}

.rag-step.search-step {
  background: var(--yellow-dim);
  border: 1px solid rgba(227, 179, 65, 0.3);
  color: var(--yellow);
}

.rag-step.retrieve-step {
  background: var(--yellow-dim);
  border: 1px solid rgba(227, 179, 65, 0.3);
  color: var(--yellow);
}

.rag-step.inject-step {
  background: var(--cyan-dim);
  border: 1px solid rgba(57, 210, 192, 0.3);
  color: var(--cyan);
}

.rag-step.model-step {
  background: var(--green-dim);
  border: 1px solid rgba(63, 185, 80, 0.3);
  color: var(--green);
}

.rag-arrow {
  font-size: 20px;
  color: var(--text-muted);
  opacity: 0;
  transition: opacity 0.3s ease;
  line-height: 1;
  padding: 4px 0;
}

.rag-arrow.visible {
  opacity: 1;
}

/* ── Skills ── */
.skill-expansion {
  margin-top: 8px;
}

.skill-expansion .arrow-down {
  text-align: center;
  font-size: 20px;
  color: var(--text-muted);
  padding: 4px 0;
}

/* ── Conclusion Full Picture ── */
.full-picture {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 10px;
}

.full-picture .context-section {
  margin-bottom: 0;
  padding: 8px 12px;
}

.full-picture .context-body {
  font-size: 11.5px;
}

.conclusion-title {
  font-family: var(--font-mono);
  font-size: 20px;
  font-weight: 600;
  text-align: center;
  color: var(--text-primary);
  padding: 16px;
  margin-bottom: 8px;
  background: linear-gradient(135deg, var(--purple-dim), var(--blue-dim));
  border-radius: 12px;
  border: 1px solid rgba(188, 140, 255, 0.3);
}

.built-with-agent {
  font-family: var(--font-sans);
  font-size: 14px;
  text-align: center;
  color: var(--text-secondary);
  padding: 12px;
  margin-top: 8px;
  opacity: 0;
  transition: opacity 0.6s ease;
  font-style: italic;
}

.built-with-agent.visible {
  opacity: 1;
}

/* ── Context Window Bar ── */
.context-bar-container {
  padding: 0 0 12px 0;
}

.context-bar-label {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
  margin-bottom: 6px;
  display: flex;
  justify-content: space-between;
}

.context-bar {
  height: 6px;
  background: var(--bg-primary);
  border-radius: 3px;
  overflow: hidden;
  border: 1px solid var(--border);
}

.context-bar-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--blue), var(--purple));
  border-radius: 3px;
  transition: width 0.6s cubic-bezier(0.4, 0, 0.2, 1);
  width: 0%;
}

/* ── Progress Bar ── */
#progress-bar {
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 16px;
  background: var(--bg-primary);
  border-top: 1px solid var(--border);
  padding: 0 20px;
}

#progress-dots {
  display: flex;
  gap: 8px;
}

.progress-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--text-muted);
  transition: background 0.3s ease, transform 0.3s ease;
  cursor: pointer;
}

.progress-dot.active {
  background: var(--blue);
  transform: scale(1.3);
}

.progress-dot.completed {
  background: var(--text-secondary);
}

#progress-label {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
}

/* ── Scrollbar ── */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--text-muted);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--text-secondary);
}

/* ── Message code blocks ── */
.message code {
  font-family: var(--font-mono);
  font-size: 13px;
  background: var(--bg-primary);
  padding: 2px 6px;
  border-radius: 4px;
}

/* ── Utility ── */
.hidden {
  display: none !important;
}

.fade-in {
  animation: fadeIn 0.4s ease;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

