}

#progress-label {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
}

#theme-toggle {
  position: absolute;
  right: 16px;
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  border-radius: 6px;
  padding: 5px 7px;
  cursor: pointer;
  color: var(--text-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.2s, color 0.2s, border-color 0.2s;
}

#theme-toggle:hover {
  background: var(--bg-secondary);
  color: var(--text-primary);
}

#progress-bar {
  position: relative;
}

/* ── Scrollbar ── */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: var(--text-muted);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--text-secondary);
}

/* ── Message code blocks ── */
.message code {
  font-family: var(--font-mono);
  font-size: 13px;
  background: var(--bg-primary);
  padding: 2px 6px;
  border-radius: 4px;
}

/* ── Title Slide ── */
.title-slide {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  text-align: center;
  padding: 40px;
  animation: fadeIn 0.6s ease;
}

.title-slide h1 {
  font-family: var(--font-sans);
  font-size: 36px;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: 16px;
  line-height: 1.2;
}

.title-slide .subtitle {
  font-family: var(--font-mono);
  font-size: 16px;
  color: var(--text-secondary);
  margin-bottom: 32px;
}

.title-slide .author {
  font-family: var(--font-sans);
  font-size: 14px;
  color: var(--text-muted);
}

/* ── Stage Title (right panel) ── */
.stage-title {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
