  color: var(--text-primary);
  margin-bottom: 12px;
}

.stage-title .stage-subtitle {
  font-family: var(--font-mono);
  font-size: 14px;
  color: var(--text-secondary);
  max-width: 400px;
  line-height: 1.6;
}

/* ── Utility ── */
.hidden {
  display: none !important;
}

.fade-in {
  animation: fadeIn 0.4s ease;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

