  color: var(--text-muted);
  opacity: 0;
  transition: opacity 0.3s ease;
  line-height: 1;
  padding: 4px 0;
}

.loop-arrow.visible {
  opacity: 1;
}

.loop-label {
  font-family: var(--font-sans);
  font-size: 12px;
  color: var(--text-muted);
  text-align: center;
  opacity: 0;
  transition: opacity 0.3s ease;
  margin-top: 4px;
  font-style: italic;
}

.loop-label.visible {
  opacity: 1;
}

.loop-brace {
  position: relative;
  margin: 4px 0;
  opacity: 0;
  transition: opacity 0.4s ease;
}

.loop-brace.visible {
  opacity: 1;
}

.loop-brace-label {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--orange);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

/* ── RAG Flow ── */
.rag-flow {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0;
  padding: 10px;
}

.rag-step {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 20px;
  border-radius: 8px;
  font-family: var(--font-mono);
  font-size: 13px;
  font-weight: 500;
  opacity: 0;
  transform: translateY(10px);
  transition: opacity 0.4s ease, transform 0.4s ease;
  min-width: 280px;
  justify-content: center;
}

.rag-step.visible {
  opacity: 1;
  transform: translateY(0);
}

.rag-step.query-step {
  background: var(--blue-dim);
  border: 1px solid rgba(88, 166, 255, 0.3);
  color: var(--blue);
}

.rag-step.search-step {
  background: var(--yellow-dim);
  border: 1px solid rgba(227, 179, 65, 0.3);
