html, body {
  height: 100%;
  background: var(--bg-primary);
  color: var(--text-primary);
  font-family: var(--font-sans);
  font-size: 16px;
  overflow: hidden;
}

/* ── App Layout ── */
#app {
  display: flex;
  height: calc(100vh - 40px);
  gap: var(--panel-gap);
}

/* ── Panels ── */
.panel {
  display: flex;
  flex-direction: column;
  background: var(--bg-secondary);
  overflow: hidden;
  transition: flex var(--transition-speed) cubic-bezier(0.4, 0, 0.2, 1);
}

#left-panel {
  flex: 1;
  min-width: 0;
}

#left-panel.full-width {
  flex: 1;
}

#left-panel.split {
  flex: 0.45;
}

#right-panel {
  flex: 0;
  opacity: 0;
  overflow: hidden;
  transition:
    flex var(--transition-speed) cubic-bezier(0.4, 0, 0.2, 1),
    opacity var(--transition-speed) ease;
}

#right-panel.visible {
  flex: 0.55;
  opacity: 1;
}

