513→  color: var(--text-muted);
514→  text-align: center;
515→  opacity: 0;
516→  transition: opacity 0.3s ease;
517→  margin-top: 4px;
518→  font-style: italic;
519→}
520→
521→.loop-label.visible {
522→  opacity: 1;
523→}
524→
525→.loop-brace {
526→  position: relative;
527→  margin: 4px 0;
528→  opacity: 0;
