      msg3user = addChatMessage('user', 'And Spain?');
      appendContextSection('user-msg', 'User', 'And Spain?');
      updateContextBar(9);
    },
    () => {
      removeChatMessage(msg3user);
      setInputText('And Spain?');
      removeLastContextSection();
      updateContextBar(8);
    }
  );

  // Step: Typing indicator
