      msg2user = addChatMessage('user', 'What about Germany?');
    },
    () => {
      removeChatMessage(msg2user);
      setInputText('What about Germany?');
    }
  );

  // Step: Typing indicator
  addStep(1,
    () => { showTypingIndicator(); },
    () => { removeTypingIndicator(); }
  );

  // Step: Assistant responds
  let msg2asst;
