    }
  );

  // Step: Callout — "The ENTIRE conversation is sent every time"
  addStep(2,
    () => {
      const sections = document.getElementById('context-sections');
      if (sections) {
        const callout = document.createElement('div');
        callout.className = 'context-callout';
