/* ── Reset & Base ── */
*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  --bg-primary: #0d1117;
  --bg-secondary: #161b22;
  --bg-tertiary: #1c2333;
  --bg-panel: #131720;
  --border: #30363d;
  --text-primary: #e6edf3;
  --text-secondary: #8b949e;
  --text-muted: #484f58;

  --blue: #58a6ff;
  --blue-dim: #1a3a5c;
  --green: #3fb950;
  --green-dim: #1a3d2a;
  --orange: #d29922;
  --orange-dim: #3d2e0a;
  --purple: #bc8cff;
  --purple-dim: #2d1a4e;
  --yellow: #e3b341;
  --yellow-dim: #3d3010;
  --red: #f85149;
  --red-dim: #3d1416;
  --cyan: #39d2c0;
  --cyan-dim: #0f3d36;
  --pink: #f778ba;
  --pink-dim: #2d1a2e;

  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  --font-mono: 'JetBrains Mono', 'Fira Code', 'Cascadia Code', monospace;

  --transition-speed: 0.4s;
  --panel-gap: 2px;
}

/* ── Light Theme ── */
:root.light {
  --bg-primary: #ffffff;
  --bg-secondary: #f6f8fa;
  --bg-tertiary: #eef1f5;
  --bg-panel: #f0f2f5;
  --border: #d0d7de;
  --text-primary: #1f2328;
  --text-secondary: #59636e;
  --text-muted: #8b949e;

  --blue: #0969da;
  --blue-dim: #ddf4ff;
  --green: #1a7f37;
  --green-dim: #dafbe1;
  --orange: #9a6700;
  --orange-dim: #fff8c5;
  --purple: #8250df;
  --purple-dim: #fbefff;
  --yellow: #9a6700;
  --yellow-dim: #fff8c5;
  --red: #cf222e;
  --red-dim: #ffebe9;
  --cyan: #0e8a7e;
  --cyan-dim: #ddf4ff;
  --pink: #bf3989;
  --pink-dim: #fbefff;
}

html, body {
  height: 100%;
  background: var(--bg-primary);
  color: var(--text-primary);
  font-family: var(--font-sans);
  font-size: 16px;
  overflow: hidden;
}

/* ── App Layout ── */
#app {
  display: flex;
  height: calc(100vh - 40px);
  gap: var(--panel-gap);
}

/* ── Panels ── */
.panel {
  display: flex;
  flex-direction: column;
  background: var(--bg-secondary);
  overflow: hidden;
  transition: flex var(--transition-speed) cubic-bezier(0.4, 0, 0.2, 1);
}

#left-panel {
  min-width: 0;
}

#left-panel.split {
  flex: 0.45;
}

#right-panel {
  flex: 0;
  opacity: 0;
  overflow: hidden;
  transition:
    flex var(--transition-speed) cubic-bezier(0.4, 0, 0.2, 1),
    opacity var(--transition-speed) ease;
}

#right-panel.visible {
  flex: 0.55;
  opacity: 1;
}

/* ── Chat Header ── */
#chat-header {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 12px 16px;
  background: var(--bg-tertiary);
  border-bottom: 1px solid var(--border);
}

.chat-header-dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: var(--text-muted);
}

.chat-header-dot:nth-child(1) { background: var(--red); }
.chat-header-dot:nth-child(2) { background: var(--orange); }
.chat-header-dot:nth-child(3) { background: var(--green); }

.chat-header-title {
  margin-left: 10px;
  font-size: 13px;
  font-weight: 500;
  color: var(--text-secondary);
}

/* ── Chat Messages ── */
#chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  scroll-behavior: smooth;
}

.message {
  max-width: 85%;
  padding: 12px 16px;
  border-radius: 12px;
  font-size: 15px;
  line-height: 1.5;
  animation: messageIn 0.3s ease;
  word-wrap: break-word;
}

.message.user {
  align-self: flex-end;
  background: var(--blue-dim);
  border: 1px solid rgba(88, 166, 255, 0.2);
  color: var(--text-primary);
  border-bottom-right-radius: 4px;
}

.message.assistant {
  align-self: flex-start;
  background: var(--bg-tertiary);
  border: 1px solid var(--border);
  color: var(--text-primary);
  border-bottom-left-radius: 4px;
}

.message .typing-indicator {
  display: inline-flex;
  gap: 4px;
  padding: 4px 0;
}

.message .typing-indicator span {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--text-secondary);
  animation: typingBounce 1.2s infinite;
}

.message .typing-indicator span:nth-child(2) { animation-delay: 0.15s; }
.message .typing-indicator span:nth-child(3) { animation-delay: 0.3s; }

@keyframes messageIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes typingBounce {
  0%, 60%, 100% { transform: translateY(0); opacity: 0.4; }
  30% { transform: translateY(-6px); opacity: 1; }
}

/* ── Chat Input ── */
#chat-input-area {
  display: flex;
  align-items: center;
  padding: 12px 16px;
  gap: 10px;
  border-top: 1px solid var(--border);
  background: var(--bg-tertiary);
}

#chat-input {
  flex: 1;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 10px 14px;
  font-family: var(--font-sans);
  font-size: 14px;
  color: var(--text-primary);
  min-height: 20px;
}

#chat-input-text {
  white-space: pre-wrap;
}

.blink {
  animation: blink 1s infinite;
  color: var(--text-secondary);
  font-weight: 300;
}

@keyframes blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

#chat-send-btn {
  background: var(--blue);
  border: none;
  border-radius: 8px;
  padding: 8px;
  cursor: pointer;
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: opacity 0.2s;
}

#chat-send-btn:hover {
  opacity: 0.8;
}

/* ── Right Panel ── */
#right-panel-header {
  display: flex;
  align-items: center;
  padding: 12px 16px;
  background: var(--bg-tertiary);
  border-bottom: 1px solid var(--border);
  min-height: 45px;
  transition: opacity 0.3s ease;
}

#right-panel-header:has(.right-panel-title:empty) {
  opacity: 0;
}

.right-panel-title {
  font-size: 13px;
  font-weight: 500;
  color: var(--text-secondary);
  font-family: var(--font-mono);
}

#right-panel-content {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.6;
}

/* ── JSON Syntax Highlighting ── */
.json-key { color: var(--blue); }
.json-string { color: var(--green); }
.json-number { color: var(--orange); }
.json-boolean { color: var(--purple); }
.json-null { color: var(--text-muted); }
.json-bracket { color: var(--text-secondary); }
.json-punctuation { color: var(--text-secondary); }

.json-block {
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 16px;
  margin-bottom: 12px;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-word;
}

.json-block.highlight-new {
  animation: highlightPulse 1s ease;
}

@keyframes highlightPulse {
  0% { border-color: var(--blue); box-shadow: 0 0 15px rgba(88, 166, 255, 0.3); }
  100% { border-color: var(--border); box-shadow: none; }
}

/* ── Context sections ── */
.context-section {
  border-radius: 8px;
  padding: 12px 16px;
  margin-bottom: 12px;
  border: 1px solid;
  animation: messageIn 0.3s ease;
}

.context-section.system {
  background: var(--purple-dim);
  border-color: rgba(188, 140, 255, 0.3);
}

.context-section.user-msg {
  background: var(--blue-dim);
  border-color: rgba(88, 166, 255, 0.3);
}

.context-section.assistant-msg {
  background: var(--green-dim);
  border-color: rgba(63, 185, 80, 0.3);
}

.context-section.thinking {
  background: var(--purple-dim);
  border-color: rgba(188, 140, 255, 0.3);
}

.context-section.tool-call {
  background: var(--orange-dim);
