      const diagram = document.getElementById('loop-diagram');
      const m2 = document.getElementById('ls-model2');
      if (m2) m2.classList.add('active');
      diagram.removeChild(diagram.lastElementChild);
      diagram.removeChild(diagram.lastElementChild);
