/* ── Reset & Base ── */
*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  --bg-primary: #0d1117;
  --bg-secondary: #161b22;
  --bg-tertiary: #1c2333;
  --bg-panel: #131720;
  --border: #30363d;
  --text-primary: #e6edf3;
  --text-secondary: #8b949e;
  --text-muted: #484f58;

  --blue: #58a6ff;
  --blue-dim: #1a3a5c;
  --green: #3fb950;
  --green-dim: #1a3d2a;
  --orange: #d29922;
  --orange-dim: #3d2e0a;
  --purple: #bc8cff;
  --purple-dim: #2d1a4e;
  --yellow: #e3b341;
  --yellow-dim: #3d3010;
  --red: #f85149;
  --red-dim: #3d1416;
  --cyan: #39d2c0;
  --cyan-dim: #0f3d36;
  --pink: #f778ba;
  --pink-dim: #2d1a2e;

  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  --font-mono: 'JetBrains Mono', 'Fira Code', 'Cascadia Code', monospace;

  --transition-speed: 0.4s;
  --panel-gap: 2px;
}

/* ── Light Theme ── */
:root.light {
  --bg-primary: #ffffff;
  --bg-secondary: #f6f8fa;
  --bg-tertiary: #eef1f5;
  --bg-panel: #f0f2f5;
  --border: #d0d7de;
  --text-primary: #1f2328;
  --text-secondary: #59636e;
  --text-muted: #8b949e;

  --blue: #0969da;
  --blue-dim: #ddf4ff;
  --green: #1a7f37;
  --green-dim: #dafbe1;
  --orange: #9a6700;
  --orange-dim: #fff8c5;
  --purple: #8250df;
  --purple-dim: #fbefff;
  --yellow: #9a6700;
  --yellow-dim: #fff8c5;
  --red: #cf222e;
  --red-dim: #ffebe9;
  --cyan: #0e8a7e;
  --cyan-dim: #ddf4ff;
  --pink: #bf3989;
  --pink-dim: #fbefff;
}

html, body {
  height: 100%;
  background: var(--bg-primary);
  color: var(--text-primary);
  font-family: var(--font-sans);
  font-size: 16px;
  overflow: hidden;
}

/* ── App Layout ── */
#app {
  display: flex;
  height: calc(100vh - 40px);
  gap: var(--panel-gap);
}

/* ── Panels ── */
.panel {
  display: flex;
  flex-direction: column;
  background: var(--bg-secondary);
  overflow: hidden;
  transition: flex var(--transition-speed) cubic-bezier(0.4, 0, 0.2, 1);
}

#left-panel {
  min-width: 0;
}

#left-panel.split {
  flex: 0.45;
}

#right-panel {
  flex: 0;
  opacity: 0;
  overflow: hidden;
  transition:
    flex var(--transition-speed) cubic-bezier(0.4, 0, 0.2, 1),
    opacity var(--transition-speed) ease;
}

#right-panel.visible {
  flex: 0.55;
  opacity: 1;
}

/* ── Chat Header ── */
#chat-header {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 12px 16px;
  background: var(--bg-tertiary);
  border-bottom: 1px solid var(--border);
}

.chat-header-dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
