            <li>"Can you pause after each phase so we can discuss"</li>
            <li>"I was thinking the right panel should always be there"</li>
            <li>"Could we add a light mode toggle"</li>
            <li>"Lets go for Agents Unmasked"</li>
            <li>"Lets move onto phase 2" <span class="prompt-meta">(all 8 stages were already built from prompt 1)</span></li>
            <li>"Can you go through the rest of the phases to check for polish"</li>
            <li>"Can you pull out all my prompts for the final slide"</li>
          </ol>
        </div>
      `;
      rightPanelContent.scrollTop = rightPanelContent.scrollHeight;
    },
    () => {
      const fp = document.getElementById('full-picture');
      fp.removeChild(fp.lastElementChild);
    }
  );
}

// ── Navigation ──

function goForward() {
  if (isAnimating) return;
  if (currentStep >= steps.length - 1) return;

  currentStep++;
  const step = steps[currentStep];
  step.forward();
  updateProgressBar(step.stage);
}

function goBack() {
  if (isAnimating) return;
  if (currentStep < 0) return;

  const step = steps[currentStep];
  step.backward();
  currentStep--;

  if (currentStep >= 0) {
    updateProgressBar(steps[currentStep].stage);
  } else {
    updateProgressBar(1);
  }
}

function jumpToStage(targetStage) {
  if (isAnimating) return;

  // Find the index of the first step in the target stage
  const targetIndex = steps.findIndex(s => s.stage === targetStage);
  if (targetIndex === -1) return;
  if (targetIndex === currentStep) return;

  // Disable animations during rapid traversal
  document.documentElement.classList.add('no-animate');

  if (targetIndex > currentStep) {
    // Fast-forward
    while (currentStep < targetIndex) {
      currentStep++;
      steps[currentStep].forward();
    }
  } else {
    // Rewind
    while (currentStep >= targetIndex) {
      steps[currentStep].backward();
      currentStep--;
    }
    // Now step forward to land on the target
    currentStep++;
    steps[currentStep].forward();
  }

  updateProgressBar(steps[currentStep].stage);

  // Re-enable animations on next frame
  requestAnimationFrame(() => {
    document.documentElement.classList.remove('no-animate');
  });
}

// ── Keyboard handler ──

document.addEventListener('keydown', (e) => {
  if (e.key === 'ArrowRight' || e.key === ' ') {
    e.preventDefault();
    goForward();
  } else if (e.key === 'ArrowLeft') {
    e.preventDefault();
    goBack();
  }
});

// ── Init ──

function init() {
  defineSteps();
  initProgressBar();
  // Start at the first step
  goForward();
}

// ── Theme toggle ──

const themeToggle = document.getElementById('theme-toggle');
const iconSun = document.getElementById('theme-icon-sun');
const iconMoon = document.getElementById('theme-icon-moon');

function setTheme(light) {
  if (light) {
    document.documentElement.classList.add('light');
    iconSun.style.display = 'none';
    iconMoon.style.display = 'block';
  } else {
    document.documentElement.classList.remove('light');
    iconSun.style.display = 'block';
    iconMoon.style.display = 'none';
  }
}

themeToggle.addEventListener('click', () => {
  const isLight = !document.documentElement.classList.contains('light');
  setTheme(isLight);
});

init();

